def modify_user(self):
    name = self.module.params['name']
    info = self.user_info()
    changed = False
    out = ''
    err = ''

    def run_command(cmd):
        rc, cmd_out, cmd_err = self.module.run_command(cmd)
        if cmd_out:
            nonlocal_out[0] += cmd_out
        if cmd_err:
            nonlocal_err[0] += cmd_err
        if rc != 0:
            return rc
        return 0

    def write_colon_file(path, lines):
        # Keep the BusyBox implementation self-contained.  Alpine systems
        # using BusyBox do not necessarily have shadow's usermod/chage
        # tools installed, so update the account databases directly.
        with open(path, 'w') as f:
            f.writelines(lines)

    nonlocal_out = ['']
    nonlocal_err = ['']

    if info is None:
        return 1, '', 'user %s does not exist' % name

    # Update fields stored in /etc/passwd.  BusyBox adduser/deluser do not
    # provide a usermod equivalent, but these fields are plain passwd(5)
    # attributes: name:passwd:uid:gid:gecos:home:shell.
    passwd_changed = False
    passwd_lines = []
    found = False
    passwd_file = '/etc/passwd'
    with open(passwd_file, 'r') as f:
        for line in f:
            if line.startswith('%s:' % name):
                found = True
                parts = line.rstrip('\n').split(':')
                if len(parts) < 7:
                    return 1, out, 'invalid passwd entry for user %s' % name

                uid = self.module.params.get('uid')
                if uid is not None and parts[2] != str(uid):
                    parts[2] = str(uid)
                    passwd_changed = True

                group = self.module.params.get('group')
                if group is not None:
                    try:
                        gid = grp.getgrnam(group).gr_gid
                    except KeyError:
                        return 1, out, 'group %s does not exist' % group
                    if parts[3] != str(gid):
                        parts[3] = str(gid)
                        passwd_changed = True

                comment = self.module.params.get('comment')
                if comment is not None and parts[4] != comment:
                    parts[4] = comment
                    passwd_changed = True

                home = self.module.params.get('home')
                old_home = parts[5]
                if home is not None and parts[5] != home:
                    parts[5] = home
                    passwd_changed = True
                    if self.module.params.get('move_home') and os.path.isdir(old_home) and not os.path.exists(home):
                        try:
                            os.rename(old_home, home)
                        except OSError as e:
                            return 1, out, 'failed to move home directory from %s to %s: %s' % (old_home, home, to_native(e))

                shell = self.module.params.get('shell')
                if shell is not None and parts[6] != shell:
                    parts[6] = shell
                    passwd_changed = True

                line = ':'.join(parts) + '\n'
            passwd_lines.append(line)

    if not found:
        return 1, out, 'user %s does not exist in %s' % (name, passwd_file)

    if passwd_changed:
        write_colon_file(passwd_file, passwd_lines)
        changed = True

    # Update password if requested.  The normal Linux implementation passes
    # this through usermod -p, which is not available on minimal BusyBox
    # Alpine installs.  Preserve update_password=on_create semantics.
    password = self.module.params.get('password')
    if password is not None and self.module.params.get('update_password') != 'on_create':
        shadow_file = '/etc/shadow'
        password_changed = False
        shadow_lines = []
        shadow_found = False
        try:
            with open(shadow_file, 'r') as f:
                for line in f:
                    if line.startswith('%s:' % name):
                        shadow_found = True
                        parts = line.rstrip('\n').split(':')
                        if len(parts) < 2:
                            return 1, out, 'invalid shadow entry for user %s' % name
                        if parts[1] != password:
                            parts[1] = password
                            password_changed = True
                        line = ':'.join(parts) + '\n'
                    shadow_lines.append(line)
            if shadow_found and password_changed:
                write_colon_file(shadow_file, shadow_lines)
                changed = True
        except IOError:
            # Some BusyBox systems may not use shadow.  Fall back to the
            # passwd password field in that case.
            passwd_password_changed = False
            passwd_lines = []
            with open(passwd_file, 'r') as f:
                for line in f:
                    if line.startswith('%s:' % name):
                        parts = line.rstrip('\n').split(':')
                        if len(parts) < 2:
                            return 1, out, 'invalid passwd entry for user %s' % name
                        if parts[1] != password:
                            parts[1] = password
                            passwd_password_changed = True
                        line = ':'.join(parts) + '\n'
                    passwd_lines.append(line)
            if passwd_password_changed:
                write_colon_file(passwd_file, passwd_lines)
                changed = True

    # Supplementary group membership.  BusyBox provides addgroup/delgroup
    # for this even though it lacks a full usermod implementation.
    groups = self.module.params.get('groups')
    if groups is not None:
        append = self.module.params.get('append')
        desired_groups = set(groups)
        current_groups = set()
        for group_entry in grp.getgrall():
            if name in group_entry.gr_mem:
                current_groups.add(group_entry.gr_name)

        primary_gid = pwd.getpwnam(name).pw_gid
        primary_group = None
        try:
            primary_group = grp.getgrgid(primary_gid).gr_name
        except KeyError:
            pass

        groups_to_add = desired_groups - current_groups
        groups_to_remove = set()
        if not append:
            groups_to_remove = current_groups - desired_groups
            if primary_group in groups_to_remove:
                groups_to_remove.remove(primary_group)

        addgroup = self.module.get_bin_path('addgroup', required=True)
        delgroup = self.module.get_bin_path('delgroup', required=True)

        for group in sorted(groups_to_add):
            rc = run_command([addgroup, name, group])
            if rc != 0:
                return rc, nonlocal_out[0], nonlocal_err[0]
            changed = True

        for group in sorted(groups_to_remove):
            rc = run_command([delgroup, name, group])
            if rc != 0:
                return rc, nonlocal_out[0], nonlocal_err[0]
            changed = True

    if changed:
        return 0, nonlocal_out[0], nonlocal_err[0]

    return None, nonlocal_out[0], nonlocal_err[0]

